"""The injected seams: retry policy, network downloader, progress observer,
and the storage budget manager. Each has exactly one job (SRP)."""
from __future__ import annotations

import threading
from abc import ABC, abstractmethod

from models import DownloadTask, NetworkError, StorageFullError


# ── WHY THIS INTERFACE ───────────────────────────────────────────────────────
# Retry math is a policy that changes independently of orchestration. Strategy.
# 🎙️ "The manager depends on this interface, so exponential vs jittered vs fixed
#     is a swap, not a rewrite."
class RetryPolicy(ABC):
    @abstractmethod
    def should_retry(self, attempt: int) -> bool: ...
    @abstractmethod
    def next_delay(self, attempt: int) -> float: ...


class ExponentialBackoffRetry(RetryPolicy):
    def __init__(self, max_attempts: int = 4, base: float = 0.5, cap: float = 30.0):
        self.max_attempts = max_attempts
        self.base = base
        self.cap = cap

    def should_retry(self, attempt: int) -> bool:
        return attempt < self.max_attempts

    def next_delay(self, attempt: int) -> float:
        # WHY: cap the backoff so a long outage doesn't push the delay to hours.
        return min(self.cap, self.base * (2 ** (attempt - 1)))


# ── WHY THIS INTERFACE ───────────────────────────────────────────────────────
# Abstracts the network as a RANGE fetch. This is the seam that makes resume
# work AND makes the network fakeable in tests.
# 🎙️ "Note it fetches by offset — that's the whole reason resume is byte-accurate."
class Downloader(ABC):
    @abstractmethod
    def fetch_chunk(self, url: str, offset: int, size: int) -> bytes: ...


class HttpDownloader(Downloader):  # pragma: no cover - illustrative
    def fetch_chunk(self, url: str, offset: int, size: int) -> bytes:
        # Real impl: GET url with header  Range: bytes=offset-(offset+size-1)
        raise NotImplementedError("wire to requests/httpx with a Range header")


# ── WHY THIS INTERFACE ───────────────────────────────────────────────────────
# The UI must reflect progress, but download logic must not depend on the UI.
# Observer.
# 🎙️ "The manager broadcasts; it knows nothing about who's listening."
class ProgressListener(ABC):
    @abstractmethod
    def on_progress(self, task: DownloadTask) -> None: ...
    @abstractmethod
    def on_state_change(self, task: DownloadTask, old) -> None: ...


class UIProgressListener(ProgressListener):
    def __init__(self):
        self.events: list[str] = []
    def on_progress(self, task: DownloadTask) -> None:
        self.events.append(f"{task.id} {task.progress_pct()}%")
    def on_state_change(self, task: DownloadTask, old) -> None:
        self.events.append(f"{task.id} {old.name}->{task.state.name}")


class StorageManager:
    # ── WHY THIS CLASS ───────────────────────────────────────────────────────
    # Enforces the storage budget and holds partial bytes. Reserve up front so a
    # doomed download never starts; discard partials on cancel/fail.
    # 🎙️ "One budget for the app. I reserve at enqueue time so we fail fast."
    def __init__(self, capacity_bytes: int):
        self._capacity = capacity_bytes
        self._used = 0
        self._partials: dict[str, bytearray] = {}
        self._lock = threading.Lock()  # storage is shared across all tasks

    def reserve(self, size: int) -> bool:
        # WHY: reservation, not just a check — count the bytes now so two
        #      concurrent enqueues can't both pass a check then overflow.
        with self._lock:
            if self._used + size > self._capacity:
                return False
            self._used += size
            return True

    def append(self, task: DownloadTask, chunk: bytes) -> None:
        with self._lock:
            self._partials.setdefault(task.id, bytearray()).extend(chunk)

    def finalize(self, task: DownloadTask) -> None:
        # Real impl: flush bytes to task.request.dest_path, fsync, atomic rename.
        with self._lock:
            self._partials.pop(task.id, None)

    def discard(self, task: DownloadTask) -> None:
        # WHY: safe to call twice — second call does nothing. Cancel and a failed
        #      finalize might both reach here.
        with self._lock:
            self._partials.pop(task.id, None)
            self._used = max(0, self._used - task.total_bytes)  # release reservation

